# ──────────────────────────────────────────
_KB_PATH = Path(__file__).parent / "knowledge.md"

def _load_knowledge() -> str:
    if _KB_PATH.exists():
        return _KB_PATH.read_text(encoding="utf-8")
    return "지식 베이스 파일(knowledge.md)이 없습니다."

KNOWLEDGE_BASE = _load_knowledge()


